using System.Net.Http.Headers; using System.Net.Http.Json; using Microsoft.AspNetCore.Mvc; namespace WebApp.Controllers;
public class BookingsController:Controller{private readonly IHttpClientFactory _f; public BookingsController(IHttpClientFactory f){_f=f;} public IActionResult Create()=>View(); [HttpPost] public async Task<IActionResult> Create(int userId,int flightId,int seatId,string passengerName,string paymentMethod){var c=_f.CreateClient("api"); var token=HttpContext.Session.GetString("token"); if(!string.IsNullOrEmpty(token)) c.DefaultRequestHeaders.Authorization=new AuthenticationHeaderValue("Bearer",token); var r=await c.PostAsJsonAsync("api/bookings",new{userId,flightId,seatId,passengerName,paymentMethod}); ViewBag.Result=await r.Content.ReadAsStringAsync(); return View();} }
